function getVibeKey(hour) {
  if (hour >= 5 && hour <= 10) return 'morning';
  if (hour >= 11 && hour <= 15) return 'midday';
  if (hour >= 16 && hour <= 19) return 'golden';
  if (hour >= 20 && hour <= 22) return 'twilight';
  return 'moonlight'; // 23, 0, 1, 2, 3, 4
}

const useVibeTheme = (created_at) => {
  return useMemo(() => {
    if (!created_at) return null;
    const date = new Date(created_at);
    const hour = date.getHours();
    const key = getVibeKey(hour);
    return { key, ...VIBE_CONFIG[key] };
  }, [created_at]);
